INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('9468a7f2-4a91-53f4-9b0d-5030038c7aab', 'd99f5952-91d8-41d5-8a1c-267609e39a20', 'There were ___ 100 people in the audience.', '觀眾大約有100人。', 'about', 'surely', 'quickly', 'deeply', '表示數量或時間的近似值 (大約)', 'about + [數字] → 大約的數量'),
('07bae832-4120-5220-896e-098520344cc7', 'ad050278-a913-4be5-b0bb-d3d91b5aa55b', 'The students were told to ___ back to their classrooms after the break.', '學生們被告知在休息時間結束後要回到教室。', 'go', 'stay', 'live', 'work', 'go (v.) 表示移動或前往某處。', '想像自己正朝著目的地「走」去。'),
('bf103383-55f6-542c-a768-9eff9adbf653', '5e767169-2c20-400a-b068-5b0d10f7fd45', 'I will ___ my homework tonight.', '我今晚會做功課。', 'do', 'make', 'take', 'play', 'do (做/進行)', 'do homework → 做功課'),
('8c75067c-3f44-5fbd-8035-d439752b04a3', 'aa399e16-a6c4-493c-b107-b99c7a6b4391', 'I want a cup ___ water.', '我想要一杯水。', 'of', 'at', 'in', 'on', 'of 用於表示量詞與內容物。', '一杯 + of + 水 = 一杯水'),
('dbe4783e-d22d-532a-b1a5-5fa7a1b8b9d3', 'c65a0c33-e9b1-448a-98db-bb934683f81c', 'It is sunny, ___ it is very cold.', '天氣晴朗，但是非常冷。', 'but', 'and', 'so', 'or', '表示轉折 (但是)', '看到 but 就要想到轉折 (轉折 → but)');
